import React, { useEffect, useRef, useState } from "react";
import {
  MapContainer,
  TileLayer,
  Marker,
  useMap,
  CircleMarker
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import "leaflet-routing-machine";

/* 🔵 USER ICON */
const userIcon = new L.DivIcon({
  className: "user-marker",
  html: `<div class="dot"></div>`,
});

/* 🔴 DEST ICON */
const destIcon = new L.DivIcon({
  className: "dest-marker",
  html: "📍",
});

/* 📍 FOLLOW USER (smooth) */
function FollowUser({ origin }) {
  const map = useMap();

  useEffect(() => {
    if (origin) {
      map.flyTo([origin.lat, origin.lon], 16, {
        duration: 1.5,
      });
    }
  }, [origin]);

  return null;
}

/* 🚗 ROUTING */
function Routing({ origin, destination, setInfo }) {
  const map = useMap();
  const routingRef = useRef(null);

  useEffect(() => {
    if (!origin || !destination) return;

    // remove old route
    if (routingRef.current) {
      map.removeControl(routingRef.current);
    }

    const control = L.Routing.control({
      waypoints: [
        L.latLng(origin.lat, origin.lon),
        L.latLng(destination.lat, destination.lon),
      ],
      lineOptions: {
        styles: [{ color: "#ff4b7d", weight: 5 }],
      },
      addWaypoints: false,
      draggableWaypoints: false,
      show: false,
    });

    control.on("routesfound", (e) => {
      const route = e.routes[0];

      const distance = (route.summary.totalDistance / 1000).toFixed(2);
      const time = (route.summary.totalTime / 60).toFixed(0);

      setInfo({ distance, time });

      map.fitBounds(route.bounds, { padding: [50, 50] });
    });

    control.addTo(map);
    routingRef.current = control;

  }, [origin, destination]);

  return null;
}

function MapView({ origin, destination, setInfo }) {
  const [infoState, setInfoState] = useState(null);
  const [search, setSearch] = useState("");

  // pass info up also
  const handleInfo = (data) => {
    setInfoState(data);
    setInfo && setInfo(data);
  };

  if (!origin) return <p>📍 Loading map...</p>;

  return (
    <div className="map-app">

      {/* 🔍 SEARCH BAR */}
      <div className="map-search">
        <input
          placeholder="Search destination..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {/* 🗺 MAP */}
      <MapContainer
        center={[origin.lat, origin.lon]}
        zoom={15}
        className="map-full"
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        {/* USER */}
        <Marker position={[origin.lat, origin.lon]} icon={userIcon} />

        <CircleMarker
          center={[origin.lat, origin.lon]}
          radius={25}
          pathOptions={{ color: "#ff4b7d", fillOpacity: 0.2 }}
        />

        {/* DEST */}
        {destination && (
          <Marker
            position={[destination.lat, destination.lon]}
            icon={destIcon}
          />
        )}

        <FollowUser origin={origin} />

        {destination && (
          <Routing
            origin={origin}
            destination={destination}
            setInfo={handleInfo}
          />
        )}
      </MapContainer>

      {/* 📊 BOTTOM PANEL */}
      <div className="bottom-panel">
        <div>
          <p>🚗 Distance</p>
          <h3>{infoState?.distance || "--"} km</h3>
        </div>

        <div>
          <p>⏱ Time</p>
          <h3>{infoState?.time || "--"} mins</h3>
        </div>
      </div>

      {/* 🎯 CENTER BUTTON */}
      <button
        className="center-btn"
        onClick={() => window.location.reload()}
      >
        📍
      </button>

    </div>
  );
}

export default MapView;
